  ('social-worker-moex-02063', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者並非後現代女性主義的行動方向？', '["倡導女性意識覺醒", "檢視權力與知識如何影響女性的世界觀", "思考改變世界之方向", "分析女性如何被社會影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02064', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '瑞摩（Reamer, 2013）認為在專業歷史發展中，社會工作的價值經歷過一些改變。總而言之，在過去一些 年來，有六個主要取向是明顯的，以下那一項是錯誤的？', '["家父長式（paternalistic）取向", "社會正義（social justice）取向", "去道德（amoralistic）的取向", "愛心（love）取向"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02065', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Munson（2002）在其《Handbook of Clinical Social Work Supervision》一書中將督導風格區分為「主動性 （active）」和「反應性（reactive）」風格。以下那一項不是主動性督導風格的展現？', '["以問題為焦點，發覺可替代的干預策略", "焦點放在治療的過程與互動的議題", "焦點放在個案的動態", "對結果的思辨"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02066', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '轉移作用（transference reactions）在下列那一種情況下較少發生？', '["每週有好多次集會（sessions）", "聚焦於早期的經驗", "聚焦於此時此地（here-and-now）", "對於內在心理（intrapsychic）過程的分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02067', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在進行方案規劃時，常需要運用現有研究結果建議的資料，請問這種方式評量需求是屬於那一類的需求 評量？', '["規範性需求", "感受性需求", "表達性需求", "相對性需求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02068', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '沛恩（Payne, 2005）在《Modern Social Work Theory》一書中提出反身－治療性觀點（reflexive-therapeutic views）為社會工作理論三類觀點之一，這類理論認為藉由促進成長及自我實現，以尋求個人、團體或社 區的最大福祉。在服務的過程中，社會工作者及案主會相互影響。以下那一個社會工作理論或觀點非屬 於反身-治療性的社會工作理論類別？', '["心理動力理論", "建構理論", "危機理論", "系統理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02069', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '功能理論（functional theory）對於當代社會工作有很大影響，其來自精神分析理論的基礎。但仍有幾點特 性不同於佛洛伊德或診斷學派。以下那一個是錯誤的陳述？', '["功能理論是基於成長心理學（psychology of growth），而非決定論", "功能理論假定機構的結構（the structure of agency）會界定服務的聚焦、方向、內容和持續性", "其將「幫助（helping）」個案的概念轉換至「治療（treating）」個案的概念", "功能理論強調「過程（process）」的概念，而非「診斷」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02070', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '心理暨社會學派（psychosocial theory）其高度適應和整合的治療目標是在創造個人與社會環境有更好的 適配（fit）。下列那一項不是其工作的目標？', '["恢復並改善個人與家庭福祉", "促成鉅視系統對家庭的回應", "促進個人人際的社會性適應", "強化個人與家庭的能力，使其從困境中復原（recover from adversity）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02071', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作的知識中，最能區辨社會工作課程與其他助人專業差異的學科是那一個？', '["社會政策", "實務方法", "研究", "社會環境中的人類行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02072', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作理論的發展或來源，主要來自三方面。試問以下那一個理論或模型屬於社會工作領域自行發展 的？', '["任務中心模型", "生態觀點", "女性主義學派", "社會支持網絡理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02073', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '針對受助者的心理需求，Biesteck提出七項原則，下列何者不在這七項之列？', '["非批判的態度", "案主的自我抉擇", "保密的原則", "價值中立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02074', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者在資源分配相關議題時，比較不是我國的優先考量？', '["依案主未來可能產出的貢獻", "人人均分的平等原則", "弱勢族群的優先和補償", "案主需求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02075', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是醫務社會工作專業價值和機構之間的衝突？', '["醫師主導性強，社工重視案主自決", "醫療團隊中的各種專業，以醫師為主要領導者", "醫師重視延續生命，社工重視案主生活品質", "醫師比較不重視案主情緒反應，社工重視案主情緒反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02076', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下身心障礙觀點的論述中，何者論述有誤？', '["文化觀點下的身心障礙是指社會結構與社會的價值觀形塑身心障礙", "目前身心障礙觀點需了解身體傷殘的來源，以醫師觀點為主", "社會性障礙造成社會排除和歧視，功能性障礙是身體傷殘引起", "「國際健康功能與身心障礙分類系統」（International Classification of Functioning, Disability and Health， 簡稱ICF）是生物心理社會模式，障礙與功能是健康狀態與環境因素交互作用下的結果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
